#include<bits/stdc++.h>
using namespace std;

int n;
bool v[10000010];
queue<int> q;
queue<int> q2;
int bfs() {
	q.push(1);
	q2.push(0);

	v[1] = 1;
	while (!q.empty()) {
		if (v[q.front() - 1] == 0 && q.front() - 1 > 0) {
			v[q.front() - 1] = 1;
			q.push(q.front() - 1);
			q2.push(q2.front() + 1);
		}
		if (v[q.front() + 1] == 0 && q.front() + 1 <= n) {
			v[q.front() + 1] = 1;
			q.push(q.front() + 1);
			q2.push(q2.front() + 1);
		}
		if (v[q.front() * 2] == 0 && q.front() * 2 <= n) {
			v[q.front() * 2] = 1;
			q.push(q.front() * 2);
			q2.push(q2.front() + 1);
		}
		if (q.front() == n) {
			return q2.front();
		}
		q.pop();
		q2.pop();
	}
	return 0;
}
int main() {
	cin >> n;
	cout << bfs();
}
